#include <iostream>

class Page {
public:
    static int s_totalVisits;
    void visit() { ++s_totalVisits; }
    static int totalVisits() { return s_totalVisits; }
};

int Page::s_totalVisits = 0;

int main() {
    Page pages[5];
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int id;
        std::cin >> id;
        pages[id - 1].visit();
    }
    std::cout << "Total visits: " << Page::totalVisits() << "\n";
    return 0;
}

