#include <iostream>

class Builder {
    int m_total{ 0 };
public:
    // BUG: should return Builder& but returns Builder (by value)
    // This means chained calls work on copies, not the original object.
    Builder add(int n) {
        m_total += n;
        return *this;
    }
    int result() const { return m_total; }
};

int main() {
    Builder b;
    b.add(2).add(3).add(4);
    std::cout << "Result: " << b.result() << "\n";
    return 0;
}

solution_code:
#include <iostream>

class Builder {
    int m_total{ 0 };
public:
    Builder& add(int n) {
        m_total += n;
        return *this;
    }
    int result() const { return m_total; }
};

int main() {
    Builder b;
    b.add(2).add(3).add(4);
    std::cout << "Result: " << b.result() << "\n";
    return 0;
}
